import { serve } from "https://deno.land/std@0.177.0/http/server.ts";

serve(async (req: Request) => {
  // Request network access without specifying allowed hosts for maximum flexibility.
  await Deno.permissions.request({ name: "net" });

  const url = new URL(req.url);
  const targetUrl = url.searchParams.get("url");

  if (!targetUrl) {
    return new Response("Please provide a 'url' query parameter.", { status: 400 });
  }

  try {
    const response = await fetch(targetUrl);
    const contentType = response.headers.get("Content-Type") || "application/octet-stream";
    const content = await response.text(); // Or response.arrayBuffer() for binary data

    return new Response(content, {
      status: response.status,
      headers: {
        "Content-Type": contentType,
        // Potentially add other headers from the original response if needed
      },
    });
  } catch (error) {
    console.error("Error fetching URL:", targetUrl, error);
    return new Response(`Failed to fetch URL: ${targetUrl}. Error: ${error.message}`, { status: 500 });
  }
});